import "./Home.css"
import React from 'react';
import { useState, useEffect } from 'react';
import EditIcon from '@mui/icons-material/Edit';

function Home() {

    const [datos, setDatos] = useState();

    useEffect(() => {
        const fetchData = async () => {
            try {
                const response = await fetch('http://127.0.0.1:8000/animales');
                const data = await response.json();
                setDatos(data);
            } catch (error) {
                console.error('Error al obtener datos de la API', error);
            }
        };

        fetchData();
    }, []);

    // console.log(datos)
    return (
        <div className="contenedor">

            <aside>
                <h1>Fincapp</h1>
                <ul>
                    <li>Lechería</li>
                    <li>Genética</li>
                    <li>Engorde</li>
                    <li>Corrales</li>
                    <li>Personal</li>
                    <li>Ventas</li>
                    <li>Rentabilidad</li>
                </ul>
            </aside>
            <main>
                <div className="contenedor_main">
                    <h1>Lechería</h1>
                    <div className='contenedor_tabla'>
                        <table>
                            <thead>
                                <tr>
                                    <th>ID</th>
                                    <th>Raza</th>
                                    <th>Cantidad</th>
                                    <th>Edad</th>
                                    <th>Corral</th>
                                    <th>Acciones</th>
                                </tr>
                            </thead>
                            <tbody>
                                {datos && datos.map((fila, index) => (
                                    <tr key={index}>
                                        <td>{fila[0]}</td> {/* ID */}
                                        <td>{fila[1]}</td> {/* Raza */}
                                        <td>{fila[11]} litros</td> {/* Cantidad */}
                                        <td>{fila[8]}</td> {/* Edad */}
                                        <td>{fila[12]}</td> {/* Corral */}
                                        <td>
                                            <EditIcon />
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>

                    </div>
                    <button>Agregar</button>

                </div>

            </main>
        </div>
    );
}

export default Home;
